$cssB64 = $parts -join ""
$cssBytes = [System.Convert]::FromBase64String($cssB64)
[System.IO.File]::WriteAllBytes("$b\src\index.css", $cssBytes)
Write-Host "OK index.css" -ForegroundColor Green

# ── build & commit ──
Write-Host "Building..." -ForegroundColor Cyan
npm run build 2>&1 | Tee-Object -Variable buildOut
$buildErr = $buildOut | Select-String "error" -CaseSensitive:$false
if ($LASTEXITCODE -eq 0) {
  git add index.html src/index.css
  git commit -m "fix: s19 - Google Fonts + CSS v7+DSv2 + cursor + light theme + dashboard + diffcard + gcw toggle"
  git push origin main
  Write-Host "DONE - aguarda Vercel" -ForegroundColor Green
} else {
  Write-Host "BUILD FALHOU:" -ForegroundColor Red
  $buildErr | ForEach-Object { Write-Host $_ -ForegroundColor Red }
}